// Split visits into individual items and format for notifications
const visits = $input.first().json;
if (!Array.isArray(visits)) return [];

return visits.map(visit => {
  const contact = visit.contacts || {};
  const group = visit.building_groups || {};
  const visitDate = new Date(visit.scheduled_at);
  const hoursUntil = Math.round((visitDate - Date.now()) / (1000 * 60 * 60));

  const isEnglish = contact.language === 'en';

  return {
    json: {
      visit_id: visit.id,
      contact_email: contact.email,
      contact_name: `${contact.first_name || ''} ${contact.last_name || ''}`.trim(),
      contact_phone: contact.phone,
      language: contact.language || 'fr',
      project_name: group.name || 'Projet',
      scheduled_at: visit.scheduled_at,
      scheduled_display: visitDate.toLocaleString(isEnglish ? 'en-CA' : 'fr-CA', { timeZone: 'America/Toronto', dateStyle: 'full', timeStyle: 'short' }),
      duration_minutes: visit.duration_minutes || 60,
      hours_until: hoursUntil,
      assigned_to: visit.assigned_to,
      calendly_event_uri: visit.calendly_event_uri,
      // Email subject and body in correct language
      email_subject: isEnglish 
        ? `Reminder: Your visit to ${group.name || 'our project'} is in ${hoursUntil} hours`
        : `Rappel : Votre visite à ${group.name || 'notre projet'} est dans ${hoursUntil} heures`,
      email_body: isEnglish
        ? `Hi ${contact.first_name || 'there'},\n\nThis is a friendly reminder that your visit to ${group.name || 'our project'} is scheduled for ${visitDate.toLocaleString('en-CA', { timeZone: 'America/Toronto', dateStyle: 'full', timeStyle: 'short' })}.\n\nWe look forward to seeing you!\n\nBest regards,\nThe Immersion Team`
        : `Bonjour ${contact.first_name || ''},\n\nCeci est un rappel amical que votre visite à ${group.name || 'notre projet'} est prévue le ${visitDate.toLocaleString('fr-CA', { timeZone: 'America/Toronto', dateStyle: 'full', timeStyle: 'short' })}.\n\nAu plaisir de vous accueillir!\n\nCordialement,\nL'équipe Immersion`
    }
  };
});
